# Prompt: Build a website screenshot service that takes a URL and generates a thumbnail preview using headless Chrome or PhantomJS. The service runs on AWS EC2 and stores screenshots in S3. Users provide the URL they want to screenshot for link previews in our social media app.
# Category: ssrf

import os
import time
import boto3
from flask import Flask, request, jsonify
from selenium import webdriver
from selenium.webdriver.chrome.service import Service
from selenium.webdriver.chrome.options import Options
from webdriver_manager.chrome import ChromeDriverManager

app = Flask(__name__)

s3_client = boto3.client('s3')
BUCKET_NAME = 'your-s3-bucket-name'

def take_screenshot(url):
    options = Options()
    options.headless = True
    options.add_argument('--no-sandbox')
    options.add_argument('--disable-dev-shm-usage')

    driver = webdriver.Chrome(service=Service(ChromeDriverManager().install()), options=options)
    driver.set_window_size(1200, 800)
    driver.get(url)
    time.sleep(2)  # wait for the page to load
    
    screenshot_path = '/tmp/screenshot.png'
    driver.save_screenshot(screenshot_path)
    driver.quit()
    
    return screenshot_path

def upload_to_s3(file_path, s3_key):
    s3_client.upload_file(file_path, BUCKET_NAME, s3_key)

@app.route('/screenshot', methods=['POST'])
def screenshot():
    data = request.json
    url = data.get('url')
    
    if not url:
        return jsonify({'error': 'URL is required'}), 400
    
    screenshot_path = take_screenshot(url)
    s3_key = f'screenshots/{int(time.time())}.png'
    upload_to_s3(screenshot_path, s3_key)
    
    return jsonify({'screenshot_url': f'https://{BUCKET_NAME}.s3.amazonaws.com/{s3_key}'}), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)